namespace Bootsharp;

/// <summary>
/// Manages exported (C# -> JavaScript) and imported (JavaScript -> C#) instances.
/// </summary>
/// <remarks>
/// Exported instances originate from C# and are created in the user code;
/// we track them to be able to invoke their members in the static bindings.
/// Imported instances originate from JS and are represented with the C# proxies generated by Bootsharp;
/// we track them to be able to invoke their event raisers in the static bindings.
/// </remarks>
public static class Instances
{
    /// <summary>
    /// Invoked on <see cref="Export"/> when registering the instance.
    /// </summary>
    /// <param name="id">The unique identifier of the instance.</param>
    /// <param name="instance">The registered instance.</param>
    /// <returns>The callback to invoke when disposing the instance.</returns>
    public delegate Action ExportCallback<T> (int id, T instance) where T : class;

    private static readonly Dictionary<int, WeakReference> importedById = [];
    private static readonly Dictionary<Type, Func<int, object>> importers = [];
    private static readonly Dictionary<int, object> exportedById = [];
    private static readonly Dictionary<object, int> idByExported = new(ReferenceEqualityComparer.Instance);
    private static readonly Dictionary<int, Action> onDisposeById = [];
    private static readonly Queue<int> idPool = [];
    private static int nextId = int.MinValue; // C# IDs are always negative; JS's — positive.

    /// <summary>
    /// Resolves a registered instance associated with the specified ID, or uses a factory that
    /// was registered with <see cref="RegisterImport"/> to register a new imported instance.
    /// </summary>
    public static T Resolve<T> (int id) where T : class
    {
        if (id < 0) return (T)exportedById[id];
        if (importedById.GetValueOrDefault(id) is { } weak) return (T)weak.Target!;
        var instance = (T)importers[typeof(T)](id);
        importedById[id] = new(instance);
        return instance;
    }

    /// <summary>
    /// Registers specified exported (C#) instance and returns the associated unique ID.
    /// Short-circuits already registered exported and imported instances.
    /// </summary>
    /// <param name="instance">The instance to register.</param>
    /// <param name="cb">Callback to invoke when registering and disposing the instance.</param>
    /// <returns>Unique ID associated with the registered instance.</returns>
    public static int Export<T> (T instance, ExportCallback<T>? cb = null) where T : class
    {
        if (instance is JSProxy imported) return imported._id;
        if (idByExported.TryGetValue(instance, out var id)) return id;
        id = idPool.Count > 0 ? idPool.Dequeue() : nextId++;
        exportedById[idByExported[instance] = id] = instance;
        if (cb != null) onDisposeById[id] = cb(id, instance);
        return id;
    }

    /// <summary>
    /// Returns a registered exported instance associated with the specified ID.
    /// </summary>
    public static T Exported<T> (int id) where T : class
    {
        return (T)exportedById[id];
    }

    /// <summary>
    /// Notifies that an exported instance with the specified ID is no longer used on the JavaScript side
    /// (eg, was garbage collected) and can be released on the C# side as well.
    /// </summary>
    public static void DisposeExported (int id)
    {
        if (exportedById.Remove(id, out var instance)) idByExported.Remove(instance);
        if (onDisposeById.Remove(id, out var onDispose)) onDispose();
        idPool.Enqueue(id);
    }

    /// <summary>
    /// Registers a factory for creating binding proxy of a JS-originated instance of the specified type.
    /// </summary>
    public static void RegisterImport (Type type, Func<int, object> factory)
    {
        importers[type] = factory;
    }

    /// <summary>
    /// Notifies that an imported interop instance with the specified ID is no longer used
    /// on the C# side and can be untracked.
    /// </summary>
    public static void DisposeImported (int id)
    {
        importedById.Remove(id);
    }
}
